const Cart = ({products, setProducts, setShowPopup}) => {
    return (
        <CartActive products={products} setProducts={setProducts} setShowPopup={setShowPopup}/>
    )
}

const CartActive = ({products, setProducts, setShowPopup}) => {
    const filteredProducts = products.filter((p) => p.amount > 0);
    const totalprice = filteredProducts.map((p) => p.amount * p.price).reduce((a, b) => a + b, 0);
    const emptycart = () => {
        setProducts(products.map(obj => {
            return {...obj, amount: obj.amount = 0};
        }))
    }
    return (
        <div className="cart sticky">
            {filteredProducts.map((p) => <ProductsInCart key={p.id} p={p}/>)}
            <p>Total price: {totalprice} €</p>
            {totalprice > 0 && <div className="cartbuttons">
                <button onClick={()=>emptycart()}>Empty Cart</button>
                <button onClick={()=>setShowPopup(true)}>Confirm Order</button>
            </div>}
        </div>
    )
}

const ProductsInCart = ({p}) => {
    return (
        <div className="cartproduct">
            <img src={p.img} alt="Product"></img>
            <p>{p.price} €</p>
            <div className="cartamount">
                <p>{p.amount}</p>
            </div>
        </div>
    )
}



export {Cart};