import { useState } from "react"

const Popup = ({products, setProducts, setShowPopup}) => {
    const [showInfo, setShowInfo] = useState(false);
    const [formData, setFormData] = useState({});
    return (
        <div className="popup">
            <span className="popupbg sticky"></span>
            <span className="popupcontent">
                {showInfo ?
                    <PopupOrderInfo products={products} setShowPopup={setShowPopup} setProducts={setProducts} setFormData={setFormData} formData={formData}/>
                :
                    <PopupForm setShowInfo={setShowInfo} setFormData={setFormData}/>
                }
            </span>
        </div>
    )
}

const PopupForm = ({setShowInfo, setFormData}) => {
    const [name, setName] = useState("");
    const [email, setEmail] = useState("");
    const [phone, setPhone] = useState("");
    const [address, setAddress] = useState("");
    const [pc, setPc] = useState("");
    const [city, setCity] = useState("");
    
    return (
        <form onSubmit={(e)=>{
            e.preventDefault();
            setFormData({name: name, email: email, phone: phone, address: address, pc: pc, city: city});
            setShowInfo(true)
        }}>
            <p>Name</p>
            <input type="text" value={name} onChange={(e) => setName(e.target.value)} required></input>
            <p>Email</p>
            <input type="text" value={email} onChange={(e) => setEmail(e.target.value)} required></input>
            <p>Phone Number</p>
            <input type="text" value={phone} onChange={(e) => setPhone(e.target.value)} required></input>
            <div>
                <p>Address</p>
                <input type="text" value={address} onChange={(e) => setAddress(e.target.value)} required></input>
                <p>Postal Code</p>
                <input type="text" value={pc} onChange={(e) => setPc(e.target.value)} required></input>
                <p>City</p>
                <input type="text" value={city} onChange={(e) => setCity(e.target.value)} required></input>
            </div>
            <input type="submit" value="Submit"></input>
        </form>
    )
}

const PopupOrderInfo = ({products, setShowPopup, setProducts, setFormData, formData}) => {
    const filteredProducts = products.filter((p) => p.amount > 0);
    const totalprice = filteredProducts.map((p) => p.amount * p.price).reduce((a, b) => a + b, 0);
    const resetinfo = () => {
        setProducts(products.map(obj => {
            return {...obj, amount: obj.amount = 0};
        }));
        setFormData({});
        setShowPopup(false);
    }

    return (
        <div className="order">
            <div className="orderinfo">
                <div>
                    <h3>Products</h3>
                    {filteredProducts.map((p) => <p key={p.id}>{p.name}</p>)}
                </div>

                <div>
                    <h3>Final Price</h3>
                    <p>{totalprice} €</p>
                </div>

                <div>
                    <h3>Address</h3>
                    <p>{formData.address}</p>
                </div>
            </div>

            <div className="orderinfofooter">
                <h4>Thank you!</h4>
                <div className="closebutton pointer">
                    <p onClick={()=>resetinfo()}>Close</p>
                </div>
            </div>
        </div>
    )
}

export {Popup};