import { useState } from 'react';
const Product = ({product, products, setProducts}) => {
    const [show, setShow] = useState(false);

    const modifyprodamount = (id, amount) => {
        setProducts(products.map(obj => {
            if(id === obj.id){
                return {...obj, amount: obj.amount + amount};
            }else{
                return obj;
            }
        }))
    }

    return (
        <div className="product">
            <p className="name">{product.name}</p>
            <img onClick={()=>setShow(!show)} src={product.img} alt="img"></img>
            <p className="price">{product.price} €</p>

            {show && <div>
                {product.amount === 0 ? 
                    <div>
                        <p>{product.type}</p>
                        <button onClick={()=>modifyprodamount(product.id, 1)}>Add to Cart</button>
                    </div>
                    :
                    <div className="amount">
                        <button onClick={()=>modifyprodamount(product.id, 1)}>+</button>
                        <p>{product.amount}</p>
                        <button onClick={()=>modifyprodamount(product.id, -1)}>-</button>  
                    </div>
                }
            </div>}
        </div>
    )
}

const Products = ({products, setProducts}) => {
    return (
        <div className="products">
            {products.map((p) => <Product key={p.id} product={p} products={products} setProducts={setProducts}/>)}
        </div>
    )
}

export {Products};